-- ===== public.biography =====
INSERT INTO public.biography (id, name_ja, name_en, body_ja, body_en, portrait_url, updated_at, name_zh, body_zh) VALUES ('f09f4844-e5cb-42b1-8afd-de704260749c','かずっち','Kazutchi','プロダンサー / 振付師。\n\nジャズ・ポップス・アイドルグループのフォーメーションダンスを軸に、ボーイズグループ育成指導、オーディション対策パフォーマンス構築、舞台表現強化トレーニング、振付設計およびステージ動線構成を行う。\n\nYOSHIKIプロデュース大型オーディション番組『YOSHIKI SUPERSTAR PROJECT X』最終合格メンバー「丸尾隼」の専属ダンス指導を担当。テレビアニメ『デジモンアドベンチャー』挿入歌「brave heart」など宮崎歩氏のライブでバックダンサーを務める。シンガーソングライター「ヨネヤマユキ」氏への振付提供をはじめ、メジャー／インディーズを問わず多数のアイドルグループへ振付・フォーメーション設計を継続的に提供。\n\nダンス未経験の一般参加者向けワークショップも定期開催し、基礎身体理解から表現構築まで段階的に育成。「物理学×心理学」としてダンスを分析し、個性を活かしながらも観客の感情を動かす構造設計を信条とする。','Professional dancer and choreographer based in Japan.\n\nSpecializing in jazz, pop, and idol-group formation dance, Kazutchi works as a boys-group development coach, audition performance designer, stage-expression trainer, and choreographer / staging director.\n\nSelected work: exclusive dance instructor for Jun Maruo, finalist of the YOSHIKI-produced audition program "YOSHIKI SUPERSTAR PROJECT X"; backup dancer for Ayumi Miyazaki, vocalist of Digimon Adventure''s insert song "brave heart"; choreographer for singer-songwriter Yuki Yoneyama, who has contributed songs to major-label idol groups; and ongoing choreography and formation design for numerous major and indie idol groups. Also leads regular workshops for absolute beginners.\n\nApproach: analyzes dance as "physics × psychology", designing structure that honors each performer''s individuality while moving the audience.',NULL,'2026-06-20 12:34:25.349144+00','卡兹奇','专业舞者 / 编舞师，活跃于日本。\n\n以爵士、流行及偶像团体队形舞为核心，从事男团育成指导、试镜表演构成、舞台表现力训练、编舞设计与舞台动线编排。\n\n主要经历：担任YOSHIKI制作大型选秀节目《YOSHIKI SUPERSTAR PROJECT X》最终合格成员"丸尾隼"专属舞蹈指导；为演唱《数码宝贝大冒险》插曲《brave heart》等知名作品的歌手宫崎步担任演唱会伴舞；为创作歌手米山雪提供编舞，其作品被多个主流偶像团体采用；持续为众多主流及独立偶像团体提供编舞与队形设计。同时定期为零基础学员举办工作坊。\n\n理念：将舞蹈作为"物理学×心理学"进行解析，在保留每位表演者个性的同时，设计能真正打动观众情感的结构。');

-- ===== public.choreography =====
INSERT INTO public.choreography (id, title_ja, title_en, year, client_ja, client_en, description_ja, description_en, image_url, video_url, created_at, updated_at, title_zh, client_zh, description_zh) VALUES ('24140aad-e5db-4d6d-aabf-042756b80a32','YOSHIKI SUPERSTAR PROJECT X 最終審査用パフォーマンス','YOSHIKI SUPERSTAR PROJECT X — Final Audition Performance','2024','丸尾隼','Jun Maruo','最終合格メンバーの個人指導。カメラワークを意識した動線設計、査基準に基づく表現力強化トレーニングを実施。','Personal direction for a finalist. Camera-aware staging and judging-criteria-based expression training.',NULL,NULL,'2026-06-15 02:02:59.224289+00','2026-06-15 02:02:59.224289+00','YOSHIKI SUPERSTAR PROJECT X 最终审查表演','丸尾隼','对最终合格成员的个人指导。结合摄像机走位的动线设计，并基于评审基准进行表现力强化训练。');
INSERT INTO public.choreography (id, title_ja, title_en, year, client_ja, client_en, description_ja, description_en, image_url, video_url, created_at, updated_at, title_zh, client_zh, description_zh) VALUES ('6da3e27f-009a-4a7c-b84f-88e686c049bf','宮崎歩 ライブ「brave heart」バックダンス','Ayumi Miyazaki Live — "brave heart" Back Dance','2024','宮崎歩','Ayumi Miyazaki','デジモンシリーズ楽曲を中心としたアニソンライブでバックダンサー兼振付補佐を担当。','Back dancer and assistant choreographer for an anime-song live centered on the Digimon series.',NULL,NULL,'2026-06-15 02:02:59.224289+00','2026-06-15 02:02:59.224289+00','宫崎步演唱会「brave heart」伴舞','宫崎步','于以数码宝贝系列乐曲为中心的动漫歌曲演唱会中担任伴舞兼编舞助理。');
INSERT INTO public.choreography (id, title_ja, title_en, year, client_ja, client_en, description_ja, description_en, image_url, video_url, created_at, updated_at, title_zh, client_zh, description_zh) VALUES ('17d01190-8038-4b6b-b50c-cfe59b9b7a20','ヨネヤマユキ 楽曲振付','Yuki Yoneyama — Song Choreography','2024','ヨネヤマユキ','Yuki Yoneyama','アニメ『デジモン』主題歌をはじめ、メジャーアイドル楽曲制作に携わるシンガーソングライターへの振付提供。','Choreography for a singer-songwriter whose credits include the Digimon anime theme and major idol-group songs.',NULL,NULL,'2026-06-15 02:02:59.224289+00','2026-06-15 02:02:59.224289+00','米山雪 歌曲编舞','米山雪','为参与《数码宝贝》主题曲及主流偶像团体作品制作的创作歌手提供编舞。');
INSERT INTO public.choreography (id, title_ja, title_en, year, client_ja, client_en, description_ja, description_en, image_url, video_url, created_at, updated_at, title_zh, client_zh, description_zh) VALUES ('8486f9e8-88af-43b6-9947-7c7801e1e969','インディーズアイドルグループ フォーメーション設計','Indie Idol Groups — Formation Design','2024','継続案件','Ongoing engagements','ライブパフォーマンス構成、フォーメーション設計、観客心理を意識した演出指導を担当。','Live performance composition, formation design, and audience-psychology-driven staging direction.',NULL,NULL,'2026-06-15 02:02:59.224289+00','2026-06-15 02:02:59.224289+00','独立偶像团体 队形设计','长期合作','负责现场表演构成、队形设计、以及结合观众心理的演出指导。');
INSERT INTO public.choreography (id, title_ja, title_en, year, client_ja, client_en, description_ja, description_en, image_url, video_url, created_at, updated_at, title_zh, client_zh, description_zh) VALUES ('bc75198b-f881-4d62-aaa8-23ee41c26238','ダンス未経験者向けワークショップ','Workshops for Absolute Beginners','2024','一般参加','Open to the public','基礎身体理解から表現構築まで段階的に育成するワークショップを定期開催。','Recurring workshops that build from foundational body awareness up to performance expression.',NULL,NULL,'2026-06-15 02:02:59.224289+00','2026-06-15 02:02:59.224289+00','零基础舞蹈工作坊','面向大众','定期举办，从基础身体认知到表现构成阶段性培养学员。');

-- ===== public.contact_info =====
INSERT INTO public.contact_info (id, email, management_ja, management_en, instagram, twitter, youtube, note_ja, note_en, updated_at, management_zh, note_zh) VALUES ('ea4bac76-1108-4657-a8fc-c5551dced5f5','contact@kazutchi.example','出演・振付・指導のご依頼は上記メールまでご連絡ください。','For performance, choreography, and coaching inquiries, please email above.',NULL,NULL,NULL,'グループ育成、オーディション対策、アイドルグループのフォーメーション振付など、お気軽にご相談ください。','Group development, audition prep, idol-group formation choreography — feel free to reach out.','2026-06-15 09:47:44.631203+00','演出、编舞、指导委托请发送邮件至上述地址。','团育成、试镜对策、偶像团体队形编舞等，欢迎随时咨询。');

-- ===== public.news =====
INSERT INTO public.news (id, title_ja, title_en, body_ja, body_en, published_at, image_url, created_at, updated_at, title_zh, body_zh) VALUES ('f815f69b-1c9d-4880-bb56-503adb922241','新規ボーイズグループ育成プロジェクト始動','New Boys-Group Development Project Launched','オーディション対策から舞台表現強化までを一貫サポートする新プロジェクトを開始しました。詳細はお問い合わせください。','A new program offering end-to-end support from audition prep to stage expression. Please contact us for details.','2026-06-01',NULL,'2026-06-15 02:02:59.224289+00','2026-06-15 02:02:59.224289+00','全新男团育成项目启动','全新项目正式启动，提供从试镜对策到舞台表现强化的一站式支持，详情请联系我们。');
INSERT INTO public.news (id, title_ja, title_en, body_ja, body_en, published_at, image_url, created_at, updated_at, title_zh, body_zh) VALUES ('ef5794cc-d3fd-4e63-84f3-0636cf654ee3','ワークショップ参加者募集中','Workshop Participants Wanted','ダンス未経験の方を対象としたワークショップを定期開催中。基礎から段階的にステップアップできます。','Recurring workshops for absolute beginners. Build skill step by step from the very basics.','2026-05-10',NULL,'2026-06-15 02:02:59.224289+00','2026-06-15 02:02:59.224289+00','工作坊招募学员中','面向零基础学员的工作坊正定期举办，可循序渐进地从基础进阶提升。');
INSERT INTO public.news (id, title_ja, title_en, body_ja, body_en, published_at, image_url, created_at, updated_at, title_zh, body_zh) VALUES ('9d4b0723-d0d3-4229-93a3-b2b22267de6b','振付提供作品リスト更新','Choreography Credits Updated','最新の振付提供作品をCHOREOGRAPHYページに追加しました。','Latest choreography credits have been added to the CHOREOGRAPHY page.','2026-04-20',NULL,'2026-06-15 02:02:59.224289+00','2026-06-15 02:02:59.224289+00','编舞作品列表更新','最新编舞作品已添加至 CHOREOGRAPHY 页面。');

